import{_ as t,c as a,a1 as i,o as n}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Footprinting using Maltego","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md"}'),o={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md"};function r(s,e,l,c,h,d){return n(),a("div",null,e[0]||(e[0]=[i('<h1 id="footprinting-using-maltego" tabindex="-1">Footprinting using Maltego <a class="header-anchor" href="#footprinting-using-maltego" aria-label="Permalink to &quot;Footprinting using Maltego&quot;">​</a></h1><p>Maltego is an open source in$$telligence and forensics application. It gathers information about a target and represents in an easily-understandable format.</p><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux virtual machine</li></ul><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Identify IP address</li><li>Identify Domain and Domain Name Schema</li><li>Identify Server Side Technology</li><li>Identify Service Oriented Architecture (SOA) information</li><li>Identify Name Server</li><li>Identify Mail Exchanger</li><li>Identify Geographical Location</li><li>Identify Entities</li><li>Discover Email addresses and Phone numbers</li></ul><p>Currently there are three versions of the Maltego client namely Maltego CE, Maltego Classic and Maltego XL. <strong>This tutorial will focus on Maltego Community Edition (CE).</strong></p><p>Kali Linux comes with Maltego installed. Launch your Maltego from the applications bar. In case it is your first time using Maltego, just select the Maltego CE (Free) edition and create a free account on <a href="https://www.paterva.com/community/community.php" target="_blank" rel="noreferrer">https://www.paterva.com/community/community.php</a></p><h2 id="maltego-basics" tabindex="-1">Maltego Basics <a class="header-anchor" href="#maltego-basics" aria-label="Permalink to &quot;Maltego Basics&quot;">​</a></h2><ol><li>Click on (+) icon located at the top-left corner of the GUI (in the toolbar) to create a new graph window (like a blank document).</li><li>Go to left panel and expand the <strong>Infrastructure</strong> node under Entity Palette. This list have a bunch of useful entities such as AS, DNS Name, Domain, MX Record, etc.</li></ol><p><img src="https://s3-eu-central-1.amazonaws.com/euc-cdn.freshdesk.com/data/helpdesk/attachments/production/2015007002780/original/tJmLPIhee9OzhB4xqVKx1pT2NGixIRpdFg.jpg?1545115008" alt="alt text" title="Entity Palette - Maltego"></p><ol start="3"><li>Drag the Website entity to your New Graph(1) section.</li><li>Rename the domain name to www.certifiedhacker.com</li></ol><h2 id="identifying-the-server-side-technology" tabindex="-1">Identifying the server side technology <a class="header-anchor" href="#identifying-the-server-side-technology" aria-label="Permalink to &quot;Identifying the server side technology&quot;">​</a></h2><ol start="5"><li>Right-click the entity and select <strong>All Transforms</strong> and click <strong>To Server Technologies [BuiltWith]</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-server-side-0.png" alt="alt text" title="Server Side Technologies"></p><p>Note: Maltego can be useful to show results in more dynamic way processing by visual demonstrating interconnected links between searched items.</p><h2 id="identifying-the-domain" tabindex="-1">Identifying the Domain <a class="header-anchor" href="#identifying-the-domain" aria-label="Permalink to &quot;Identifying the Domain&quot;">​</a></h2><ol start="6"><li>Create a new graph or delete/save the previous results.</li><li>Right-click the Domain entity and select <strong>All Transforms -&gt; To Domains [DNS]</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/dd19c689c25ad5a9f86d5c4450b26bb5f82eadc9/maltego-DNS-names.png" alt="alt text" title="DNS Names"></p><p>This transform will attempt to test name schemas against a domain and try to identify a specific name schema for the domain.</p><h2 id="identifying-the-soa-information" tabindex="-1">Identifying the SOA information <a class="header-anchor" href="#identifying-the-soa-information" aria-label="Permalink to &quot;Identifying the SOA information&quot;">​</a></h2><ol start="8"><li>Create a new graph or delete/save the previous results.</li><li>Right-click the Domain entity and select <strong>All Transforms -&gt; To DNS Name - SOA (Start of Authority)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-DNS-SOA-2.png" alt="alt text" title="DNS Name - SOA"></p><h2 id="identifying-the-mail-exchanger" tabindex="-1">Identifying the Mail Exchanger <a class="header-anchor" href="#identifying-the-mail-exchanger" aria-label="Permalink to &quot;Identifying the Mail Exchanger&quot;">​</a></h2><ol start="10"><li>Create a new graph or delete/save the previous results.</li><li>Right-click the Domain entity and select <strong>All Transforms -&gt; To DNS Name - MX (mail server)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-MX-NameServers-3.png" alt="alt text" title="DNS MX Server"></p><h2 id="identifying-the-name-server" tabindex="-1">Identifying the Name Server <a class="header-anchor" href="#identifying-the-name-server" aria-label="Permalink to &quot;Identifying the Name Server&quot;">​</a></h2><ol start="12"><li>Create a new graph or delete/save the previous results.</li><li>Right-click the Domain entity and select <strong>All Transforms -&gt; To DNS Name - NS (name server)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-DNS-Name-Servers-4.png" alt="alt text" title="NS"></p><h2 id="identifying-the-ip-address-location-and-whois" tabindex="-1">Identifying the IP Address, Location and Whois <a class="header-anchor" href="#identifying-the-ip-address-location-and-whois" aria-label="Permalink to &quot;Identifying the IP Address, Location and Whois&quot;">​</a></h2><ol start="12"><li>Create a new graph or delete/save the previous results.</li><li>Right-click the Website entity and select <strong>All Transforms -&gt; To IP address [DNS]</strong>.</li><li>Right-click the IP entity and select <strong>All Transforms -&gt; To Location [city, country]</strong>.</li><li>Right-click the Website entity and select <strong>All Transforms -&gt; To entities from whois [IBM Watson]</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-WebSite-IP-Location-WhoisOnDomain-5.png" alt="alt text" title="IP Address, Location"></p><h2 id="in-conclusion" tabindex="-1">In conclusion: <a class="header-anchor" href="#in-conclusion" aria-label="Permalink to &quot;In conclusion:&quot;">​</a></h2><p>Maltego is a powerful tool, you can extract a broad type of information through the network, technologies and personnel(email, phone number, twitter).</p><p>By extracting all this information, an attacker can perform different type of malicious activity.</p><ul><li><p>The built-in technologies of the server: attackers might search for vulnerabilities related to any of them and simulate exploitation techniques.</p></li><li><p>SOA information: also can be useful for attackers, they can abuse this information to find vulnerabilities in their services and architectures and exploit them.</p></li><li><p>Name Server: attackers can exploit NS using malicious techniques like DNS hijacking and URL redirection.</p></li><li><p>IP addresses: attackers can abuse the IP address by scanning and searching for open ports and vulnerabilities, and thereby attempt to intrude in the network and exploit them.</p></li><li><p>Geographical location: attackers can perform social engineering attacks to leverage sensitive information.</p></li></ul>',36)]))}const f=t(o,[["render",r]]);export{m as __pageData,f as default};
